# Without defaultdict — error-prone pattern:
d = {}
for word in words:
    if word not in d:
        d[word] = []
    d[word].append(word)

# With defaultdict — clean and safe:
from collections import defaultdict

d = defaultdict(list)
for word in words:
    d[word].append(word)   # No check needed — list() is called on first access

students = [('Alice', 'Math'), ('Bob', 'Science'), ('Alice', 'Science'), ('Bob', 'Math')]

by_student = defaultdict(list)
for name, subject in students:
    by_student[name].append(subject)

# {'Alice': ['Math', 'Science'], 'Bob': ['Science', 'Math']}

from collections import ChainMap

defaults = {'color': 'red', 'user': 'guest', 'timeout': 30}
user_settings = {'color': 'blue', 'timeout': 60}
env_vars = {'user': 'admin'}

config = ChainMap(env_vars, user_settings, defaults)

print(config['user'])     # 'admin'    — from env_vars
print(config['color'])    # 'blue'     — from user_settings
print(config['timeout'])  # 60         — from user_settings

class Point:
    def __init__(self, x, y):
        self.x = x
        self.y = y

    def __repr__(self):
        return f'Point(x={self.x}, y={self.y})'

    def __eq__(self, other):
        if not isinstance(other, Point):
            return NotImplemented
        return self.x == other.x and self.y == other.y

@dataclass
class Bad:
    x: int = 0
    y: int         # SyntaxError: non-default argument follows default argument

# WRONG — all instances share the SAME list object:
@dataclass
class Bad:
    items: list = []   # TypeError raised by dataclasses

# CORRECT — each instance gets its own new list:
@dataclass
class Good:
    items: list = field(default_factory=list)

@dataclass(frozen=True)
class Color:
    r: int
    g: int
    b: int

red = Color(255, 0, 0)
# red.r = 128   # Raises FrozenInstanceError

# Hashable — can be used as dict key or in a set:
palette = {red, Color(0, 255, 0)}

from dataclasses import dataclass, field
import math

@dataclass
class Circle:
    radius: float
    area: float = field(init=False, repr=True)  # Not set by user

    def __post_init__(self):
        if self.radius <= 0:
            raise ValueError(f"Radius must be positive, got {self.radius}")
        self.area = math.pi * self.radius ** 2

c = Circle(5.0)
print(c)          # Circle(radius=5.0, area=78.53981633974483)
# Circle(-1)      # ValueError: Radius must be positive, got -1

@dataclass
class Animal:
    name: str
    weight: float

@dataclass
class Dog(Animal):
    breed: str
    trained: bool = False

d = Dog('Rex', 30.0, 'Labrador')
# Dog(name='Rex', weight=30.0, breed='Labrador', trained=False)

